import { ReactNode } from "react";
import TabBar from "./TabBar";

interface LayoutProps {
  children: ReactNode;
  showTabBar?: boolean;
}

export default function Layout({ children, showTabBar = true }: LayoutProps) {
  return (
    <div className="flex flex-col bg-surface h-full">
      <main className="flex-1 overflow-hidden animate-fade-in">{children}</main>
      {showTabBar && <TabBar />}
    </div>
  );
}
